var e=[{id:`L2_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`누나들을…… 지킨다고……? 누가 누굴?`,JPN:`みんなを……守る……？　誰が誰を？`,ENG:`Protect... them...? Says who?`,TWN:`保護……姊姊……？誰保護誰？`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`하아…….`,JPN:`はあ……`,ENG:`*Sigh*`,TWN:`哀……`},stage:{bg:`GAMECIRCLE_04`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`젠장, 대체…… 왜 하필 거기서 그딴 소리를 지껄인거야……!`,JPN:`ちくしょう、どうして……よりによって、あそこであんなことを……！`,ENG:`Dang it, Why... why did I say something so stupid...!`,TWN:`真丟人，我幹嘛……我那時候在胡言亂語什麼……！`},stage:{bg:`GAMECIRCLE_04`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`적어도 좀 더 멋있는 말이 있었을 거 아니야……. 이 멍청아……!`,JPN:`せめてもっとカッコいい言葉があるはずだろう……このアホ……！`,ENG:`I should have come up with something cooler...! Agh, I’m an idiot...!`,TWN:`應該有更帥氣的台詞吧……我這個蠢蛋……！`},stage:{bg:`GAMECIRCLE_04`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`으으……!`,JPN:`うう……！`,ENG:`Urgh...!`,TWN:`呃……！`},stage:{bg:`GAMECIRCLE_04`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`꺼내지 말 걸 그랬어……!`,JPN:`取り出さなければよかった……！`,ENG:`I shouldn’t have brought this up...!`,TWN:`我不該挖出來的……！`},stage:{bg:`GAMECIRCLE_04`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`흑역사는 흑역사인대로 묻어둘 걸 그랬어……!`,JPN:`黒歴史は黒歴史のままに埋めとけばよかった……！`,ENG:`I should have kept it buried, deep inside my head...!`,TWN:`黑歷史就應該埋起來……！`},stage:{bg:`GAMECIRCLE_04`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`누나들도 마찬가지야. 이딴 버그 망겜을 잘도 2000개씩이나 찍었군.`,JPN:`みんなも同じだ。よくもこんなバグだらけのクソゲーを2000枚も発注したもんだ。`,ENG:`That goes the same for the girls. How on earth did they manage to order 2000 discs of this ridiculous game?`,TWN:`姊姊們也是，這種爛遊戲還給我下單2000片！`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`정말…… 다들 제 정신이 아니었어……! 너무 무모하잖아, 너무……!`,JPN:`本当に……みんな正気じゃなかったんだ……！　無謀すぎるんだよ、まったく……！`,ENG:`Really... We were all so reckless back then...! Way too wild...!`,TWN:`我看……大家真的都腦袋有問題……！做事都沒經過大腦思考……！`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`후후…….`,JPN:`ふふ……`,ENG:`Ha ha...`,TWN:`呵呵……`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`……하지만.`,JPN:`……でも。`,ENG:`...But really...`,TWN:`……不過，`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`하지만 역시 그립네. 그때가.`,JPN:`でも、やっぱり懐かしいな。あの時が。`,ENG:`I do miss those days.`,TWN:`話說回來，還真懷念那個時候。`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`그 시절 꼬맹이인 내가…… 지금의 나를 보면 한심하다고 생각하겠지?`,JPN:`あの頃、ガキだった私が……今の私を見たら情けないと思うだろうな。`,ENG:`I bet the younger me... would consider the man I am as pathetic.`,TWN:`年輕時候的我……看到現在的我，應該會覺得很糟糕吧？`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`적어도 그 녀석은 지금 나처럼 겁쟁이는 아니었으니까.`,JPN:`少なくともあいつは、今の私のような弱虫ではなかったんだから。`,ENG:`At least I used to be less of a coward back then.`,TWN:`至少年輕時候的我不像現在的我是個膽小鬼。`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CHEOLSU_NPC_GAMECIRCLE_NULL`,text:{KOREA:`그래, 40년 전의…… <color=#ffd34c>나</color>는 말이지.`,JPN:`そう、40年前の……<color=#ffd34c>僕</color>はな。`,ENG:`Yes... <color=#ffd34c>The younger me</color>, 40 years ago...`,TWN:`沒錯，那個40年前的……<color=#ffd34c>我</color>。`},stage:{bg:`GAMECIRCLE_03`,bgm:`THEMA_GAMECIRCLE_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};